import SwiftUI
struct ContentView: View {
    @State private var name: String?
    var body: some View {
        Text(name).if $name != nil
    }
}

struct Counter: @main {
    @State private var count = 0
    var body: some View {
        VStack {
            Text("Count: ")
            Text(count)
            Button("Increment") { count += 1 }
        }
    }
}

